import{_ as a,o as e,c as d,ag as i}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Alias Default | Dotfiles (ID)","titleTemplate":":title","description":"Alias shell esensial untuk navigasi, kontrol sistem, dan tugas sehari-hari. Sederhanakan alur kerja terminal dengan pintasan universal ini.","frontmatter":{"title":"Alias Default | Dotfiles","description":"Alias shell esensial untuk navigasi, kontrol sistem, dan tugas sehari-hari. Sederhanakan alur kerja terminal dengan pintasan universal ini.","lang":"id-ID","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Default preview","canonical":"/id/aliases/default/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Default","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Default - Dotfiles (ID)","permalink":"/id/aliases/default/","sidebar":true,"meta":[{"name":"keywords","content":"default aliases, shell aliases, terminal shortcuts, dotfiles, bash aliases"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Alias Default - Dotfiles"},{"name":"twitter:description","content":"Alias shell esensial untuk navigasi, kontrol sistem, dan tugas sehari-hari."},{"name":"og:title","content":"Alias Default - Dotfiles"},{"name":"og:description","content":"Alias shell esensial untuk navigasi, kontrol sistem, dan tugas sehari-hari."},{"name":"og:image:alt","content":"Dotfiles - Dirancang sederhana untuk menyesuaikan kehidupan shell Anda"},{"name":"og:locale","content":"id_ID"}]},"headers":[],"relativePath":"id/aliases/default/index.md","filePath":"id/aliases/default/index.md","lastUpdated":1773010926000}'),o={name:"id/aliases/default/index.md"};function r(n,t,s,l,c,h){return e(),d("div",null,[...t[0]||(t[0]=[i('<h1 id="alias-default" tabindex="-1">Alias Default <a class="header-anchor" href="#alias-default" aria-label="Permalink to &quot;Alias Default&quot;">​</a></h1><p>Pintasan shell esensial untuk tugas terminal sehari-hari.</p><h2 id="ikhtisar" tabindex="-1">Ikhtisar <a class="header-anchor" href="#ikhtisar" aria-label="Permalink to &quot;Ikhtisar&quot;">​</a></h2><p>Alias default menyediakan koleksi pintasan shell universal yang mempercepat operasi terminal umum. Alias ini didefinisikan di <code>default.aliases.sh</code> dan dimuat secara otomatis oleh chezmoi di semua shell yang didukung.</p><p>Pintasan ini mencakup utilitas umum, perintah keluar, diagnostik jaringan, pemantauan sistem, dan navigasi sistem file.</p><h2 id="referensi" tabindex="-1">Referensi <a class="header-anchor" href="#referensi" aria-label="Permalink to &quot;Referensi&quot;">​</a></h2><h3 id="umum" tabindex="-1">Umum <a class="header-anchor" href="#umum" aria-label="Permalink to &quot;Umum&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Perintah</th><th>Deskripsi</th></tr></thead><tbody><tr><td><code>da</code></td><td><code>date &quot;+%Y-%m-%d %A %T %Z&quot;</code></td><td>Tampilkan tanggal dan waktu saat ini</td></tr><tr><td><code>p</code></td><td><code>pwd</code></td><td>Tampilkan direktori kerja</td></tr><tr><td><code>path</code></td><td><code>echo ${PATH//:/\\\\n}</code></td><td>Tampilkan variabel PATH dengan baris baru</td></tr><tr><td><code>r</code></td><td><code>reload</code></td><td>Muat ulang shell</td></tr><tr><td><code>t</code></td><td><code>tail -f</code></td><td>Ikuti output file secara real-time</td></tr><tr><td><code>wk</code></td><td><code>date +%V</code></td><td>Tampilkan nomor minggu saat ini</td></tr></tbody></table><h3 id="keluar-dan-shutdown" tabindex="-1">Keluar dan Shutdown <a class="header-anchor" href="#keluar-dan-shutdown" aria-label="Permalink to &quot;Keluar dan Shutdown&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Perintah</th><th>Deskripsi</th></tr></thead><tbody><tr><td><code>q</code></td><td><code>exit</code></td><td>Keluar dari shell</td></tr><tr><td><code>quit</code></td><td><code>exit</code></td><td>Keluar dari shell</td></tr><tr><td><code>bye</code></td><td><code>exit</code></td><td>Keluar dari shell</td></tr><tr><td><code>:q</code></td><td><code>exit</code></td><td>Keluar dari shell (gaya vim)</td></tr><tr><td><code>halt</code></td><td><code>sudo /sbin/halt</code></td><td>Hentikan sistem</td></tr><tr><td><code>poweroff</code></td><td><code>sudo /sbin/shutdown</code></td><td>Matikan sistem</td></tr><tr><td><code>reboot</code></td><td><code>sudo /sbin/reboot</code></td><td>Mulai ulang sistem</td></tr></tbody></table><h3 id="riwayat" tabindex="-1">Riwayat <a class="header-anchor" href="#riwayat" aria-label="Permalink to &quot;Riwayat&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Perintah</th><th>Deskripsi</th></tr></thead><tbody><tr><td><code>h</code></td><td><code>history</code></td><td>Tampilkan riwayat perintah</td></tr><tr><td><code>history</code></td><td><code>fc -il 1</code></td><td>Tampilkan riwayat dengan timestamp ISO 8601</td></tr></tbody></table><h3 id="jaringan" tabindex="-1">Jaringan <a class="header-anchor" href="#jaringan" aria-label="Permalink to &quot;Jaringan&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Perintah</th><th>Deskripsi</th></tr></thead><tbody><tr><td><code>ifconfig</code></td><td><code>sudo ifconfig</code></td><td>Konfigurasi antarmuka jaringan</td></tr><tr><td><code>ipinfo</code></td><td><code>ipconfig getpacket en0</code></td><td>Dapatkan parameter jaringan untuk en0</td></tr><tr><td><code>nls</code></td><td><code>sudo lsof -i -P | grep LISTEN</code></td><td>Tampilkan listener jaringan aktif</td></tr><tr><td><code>op</code></td><td><code>sudo lsof -i -P</code></td><td>Daftar port terbuka</td></tr><tr><td><code>ping</code></td><td><code>ping -c 5</code></td><td>Ping dengan batas 5 paket</td></tr><tr><td><code>ports</code></td><td><code>netstat -tulan</code></td><td>Daftar semua port yang mendengarkan</td></tr></tbody></table><h3 id="pemantauan-sistem" tabindex="-1">Pemantauan Sistem <a class="header-anchor" href="#pemantauan-sistem" aria-label="Permalink to &quot;Pemantauan Sistem&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Perintah</th><th>Deskripsi</th></tr></thead><tbody><tr><td><code>top</code></td><td><code>sudo btop</code></td><td>Monitor proses interaktif</td></tr><tr><td><code>spd</code></td><td><code>sudo rm -rf /private/var/log/asl/*</code></td><td>Bersihkan file log ASL</td></tr></tbody></table><h3 id="utilitas" tabindex="-1">Utilitas <a class="header-anchor" href="#utilitas" aria-label="Permalink to &quot;Utilitas&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Perintah</th><th>Deskripsi</th></tr></thead><tbody><tr><td><code>ctf</code></td><td><code>ls -1 | wc -l</code></td><td>Hitung file di direktori saat ini</td></tr><tr><td><code>qfind</code></td><td><code>find . -name</code></td><td>Pencarian file cepat</td></tr><tr><td><code>reload</code></td><td><code>exec $SHELL -l</code></td><td>Muat ulang shell</td></tr><tr><td><code>wth</code></td><td><code>curl -s &quot;wttr.in/?format=3&quot;</code></td><td>Dapatkan cuaca saat ini</td></tr></tbody></table>',18)])])}const p=a(o,[["render",r]]);export{m as __pageData,p as default};
